#!run
import {t} from "@hoge1e3/dom";
//import css from "@acepad/css";
import {did} from "@hoge1e3/dom-id";
import {c} from "@hoge1e3/component";
import {show} from "./acepad-widget.js";
import {fromVal} from "@hoge1e3/immer-path-ref";
import {ref,V,E,set,change} from "@hoge1e3/ref";
export function main(...a){
  const [o,...args]=this.pickOptions(a);
  const id=did("w");
  //css container id
  const csscid=id.cssc;
  const rdom=o.css?
    t.div(
      css(this.resolve(o.css),csscid),
      t.div({id:csscid, style:"width:100%;height:100%;overflow:scroll;"},
        t.div({id}))
    ):t.div({id});
  const w=show(rdom,{overlay:true});
  Object.assign(w,{
    r:fromVal,
    t,c,id,V,E,set,change
  });
  let dom=args[0]||o.wmain;
  if(typeof dom==="function"){
    dom=dom.call(this,w);
  }
  if(dom){
    if (!dom.id) dom.id=id;
    w.print(dom);
  }
  return w;
}
export function css(file,id){
  const cont=`#${id} {
  ${file.text()}
}`;
  const s=document.createElement("style");
  s.innerHTML=cont;
  //console.log(cont)
  return(s);
} 